import importlib.util
import io
import json
import uuid
from pathlib import Path

import pytest

AC_UID = "e496339696fe9ba1"
AC_TYPE = "hook"

_HOOK_PATH = (
    Path(__file__).resolve().parents[3] / "hooks" / "pretool-orchestrator-gate.py"
)


def _load_module():
    spec = importlib.util.spec_from_file_location(
        f"orchestrator_gate_{uuid.uuid4().hex}", _HOOK_PATH
    )
    mod = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(mod)
    return mod


def _drive_main(mod, monkeypatch, payload):
    monkeypatch.setattr("sys.stdin", io.StringIO(json.dumps(payload)))
    try:
        mod.main()
        return 0
    except SystemExit as exc:
        code = exc.code
        if code is None:
            return 0
        return int(code)


def test_AC2(tmp_path, monkeypatch):
    """
    GIVEN: a pre-seeded temp state {schema_version:2, per_tool_counts:{'Edit':1}, bash_consecutive:{'last_tool':'Bash','count':3}}, resolved to the same path main() will use (monkeypatch get_streak_state_file OR a unique sid)
    WHEN:  main() processes a main-agent Agent dispatch (stdin JSON {'tool_name':'Agent','session_id':<sid>}; no agent_id; no /do; no /allow)
    THEN:  main() does NOT block (normal return or SystemExit code 0/None) and persists bash_consecutive == {'last_tool':'Agent','count':0} with per_tool_counts preserved == {'Edit':1}; a subsequent Bash starts a fresh streak
    """
    mod = _load_module()

    sid = f"ac2-{uuid.uuid4().hex}"
    state_file = tmp_path / "ac2.json"
    monkeypatch.setattr(mod, "get_streak_state_file", lambda _sid: state_file)

    # Pre-seed the exact state.
    state_file.write_text(json.dumps({
        "schema_version": 2,
        "per_tool_counts": {"Edit": 1},
        "bash_consecutive": {"last_tool": "Bash", "count": 3},
    }))

    # Main-agent Agent dispatch: no agent_id, no /do, no /allow.
